#include <iostream>
#include <fstream>
#include <string>
using namespace std;

int main() {
    ofstream fout("output.txt");
    fout << "Hello, File!" << endl;
    fout << 42 << endl;
    fout.close();

    ifstream fin("output.txt");
    string line;
    while (getline(fin, line)) {
        cout << line << endl;
    }
    fin.close();
    return 0;
}

